class Solution:
    def minimumBeautifulSubstrings(self, s):
        n = len(s)
        best = [None]

        def rec(start, count):
            if best[0] is not None and count >= best[0]:
                return
            if start == n:
                if best[0] is None or count < best[0]:
                    best[0] = count
                return
            if s[start] == '0':
                return
            val = 0
            for end in range(start, n):
                val = val * 2 + (1 if s[end] == '1' else 0)
                if _is_power_of_5(val):
                    rec(end + 1, count + 1)

        rec(0, 0)
        return best[0] if best[0] is not None else -1

