def _is_power_of_5(x):
    if x <= 0:
        return False
    while x % 5 == 0:
        x //= 5
    return x == 1

class Solution:
    def minimumBeautifulSubstrings(self, s):
        n = len(s)
        INF = float('inf')
        dp = [INF] * (n + 1)
        dp[n] = 0
        for i in range(n - 1, -1, -1):
            if s[i] == '0':
                continue
            val = 0
            for j in range(i, n):
                val = val * 2 + (1 if s[j] == '1' else 0)
                if dp[j + 1] != INF and _is_power_of_5(val):
                    dp[i] = min(dp[i], dp[j + 1] + 1)
        return dp[0] if dp[0] != INF else -1

