function isPowerOf5(x) {
    if (x <= 0) return false;
    while (x % 5 === 0) x = Math.floor(x / 5);
    return x === 1;
}

var minimumBeautifulSubstrings = function(s) {
    const n = s.length;
    const INF = Infinity;
    const dp = new Array(n + 1).fill(INF);
    dp[n] = 0;
    for (let i = n - 1; i >= 0; i--) {
        if (s[i] === '0') continue;
        let val = 0;
        for (let j = i; j < n; j++) {
            val = val * 2 + (s[j] === '1' ? 1 : 0);
            if (dp[j + 1] !== INF && isPowerOf5(val)) {
                dp[i] = Math.min(dp[i], dp[j + 1] + 1);
            }
        }
    }
    return dp[0] !== INF ? dp[0] : -1;
};
